begin;alter table public.lead_visits add column if not exists preparation_snapshot jsonb not null default'{}',add column if not exists preparation_completed_at timestamptz,add column if not exists outcome_key text check(outcome_key is null or outcome_key in('high_interest','needs_comparison','needs_simulation','not_fit','reschedule','no_show')),add column if not exists objection_keys text[]not null default'{}',add column if not exists next_step_key text check(next_step_key is null or next_step_key in('send_material','create_simulation','schedule_follow_up','request_proposal_review','show_alternative','reschedule_visit','close_lost')),add column if not exists result_recorded_at timestamptz;create table if not exists public.visit_assistance_events(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id)on delete cascade,lead_id uuid not null references public.leads(id)on delete cascade,visit_id uuid not null references public.lead_visits(id)on delete cascade,actor_id uuid not null references public.profiles(id),event_type text not null check(event_type in('prepared','result_recorded','proposal_review_suggested')),outcome_key text,next_step_key text,created_at timestamptz not null default now());alter table public.visit_assistance_events enable row level security;create policy visit_assistance_events_scope on public.visit_assistance_events for select to authenticated using(organization_id=(select public.current_organization_id())and(select private.can_view_lead(lead_id)));revoke all on public.visit_assistance_events from anon;revoke insert,update,delete on public.visit_assistance_events from authenticated;grant select on public.visit_assistance_events to authenticated;grant all on public.visit_assistance_events to service_role;
create or replace function public.record_structured_visit_result(p_actor_id uuid,p_organization_id uuid,p_lead_id uuid,p_visit_id uuid,p_outcome_key text,p_objection_keys text[],p_next_step_key text)returns jsonb language plpgsql security definer set search_path=''as $$declare v public.lead_visits%rowtype;allowed_objections text[]:=array['price','payment_flow','location','unit_profile','delivery','trust','decision_maker','availability'];begin select*into v from public.lead_visits where id=p_visit_id and lead_id=p_lead_id and organization_id=p_organization_id for update;if v.id is null or v.broker_id<>p_actor_id then raise exception'visit_result_owner_only';end if;if p_outcome_key not in('high_interest','needs_comparison','needs_simulation','not_fit','reschedule','no_show')or not coalesce(p_objection_keys,'{}')<@allowed_objections or p_next_step_key not in('send_material','create_simulation','schedule_follow_up','request_proposal_review','show_alternative','reschedule_visit','close_lost')then raise exception'visit_result_invalid';end if;if v.status not in('completed','no_show')then raise exception'visit_result_status_invalid';end if;update public.lead_visits set outcome_key=p_outcome_key,objection_keys=coalesce(p_objection_keys,'{}'),next_step_key=p_next_step_key,result_recorded_at=now()where id=v.id;insert into public.visit_assistance_events(organization_id,lead_id,visit_id,actor_id,event_type,outcome_key,next_step_key)values(p_organization_id,p_lead_id,v.id,p_actor_id,'result_recorded',p_outcome_key,p_next_step_key);return jsonb_build_object('visitId',v.id,'outcome',p_outcome_key,'nextStep',p_next_step_key,'proposalCreated',false,'messageSent',false,'humanConfirmationRequired',true);end$$;revoke all on function public.record_structured_visit_result(uuid,uuid,uuid,uuid,text,text[],text)from public,anon,authenticated;grant execute on function public.record_structured_visit_result(uuid,uuid,uuid,uuid,text,text[],text)to service_role;commit;
